import{_ as e,o as t,c as l,ag as r}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"Claude Code Hub (CCH)","description":"","frontmatter":{},"headers":[],"relativePath":"tools/claude-code-hub.md","filePath":"tools/claude-code-hub.md"}'),i={name:"tools/claude-code-hub.md"};function o(s,a,d,n,h,c){return t(),l("div",null,[...a[0]||(a[0]=[r(`<h1 id="claude-code-hub-cch" tabindex="-1">Claude Code Hub (CCH) <a class="header-anchor" href="#claude-code-hub-cch" aria-label="Permalink to &quot;Claude Code Hub (CCH)&quot;">​</a></h1><p>团队级多供应商 AI Coding 代理调度平台</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><table tabindex="0"><thead><tr><th>资源</th><th>地址</th></tr></thead><tbody><tr><td>官网</td><td><a href="https://claude-code-hub.app" target="_blank" rel="noreferrer">claude-code-hub.app</a></td></tr><tr><td>官方文档</td><td><a href="https://claude-code-hub.app/docs" target="_blank" rel="noreferrer">claude-code-hub.app/docs</a></td></tr><tr><td>GitHub</td><td><a href="https://github.com/ding113/claude-code-hub" target="_blank" rel="noreferrer">ding113/claude-code-hub</a></td></tr></tbody></table><h2 id="工具介绍" tabindex="-1">工具介绍 <a class="header-anchor" href="#工具介绍" aria-label="Permalink to &quot;工具介绍&quot;">​</a></h2><p>Claude Code Hub (CCH) 是一个服务器部署的多租户 AI Coding 工具调度平台，帮助团队统一管理 Claude、Codex、Gemini 等多家 AI 服务商，实现智能负载均衡与自动故障转移。</p><div class="tip custom-block"><p class="custom-block-title">💡 适用场景</p><ul><li>中小软件公司：需要合规审计、访问控制和完整日志</li><li>创业公司：预算有限，需要精细的成本控制和多维限流</li><li>AI 驱动开发团队：重度依赖 AI Coding，需要高可用和自动故障转移</li><li>敏捷开发团队：多人共用 AI 工具，需要统一管理和用量追踪</li></ul></div><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><ul><li><strong>OpenAI 兼容层</strong>：支持 <code>/v1/chat/completions</code> 端点，无缝对接现有工具链</li><li><strong>Session 管理</strong>：5 分钟上下文缓存，同一会话自动路由到相同供应商，提高缓存命中率</li><li><strong>实时监控与统计</strong>：仪表盘展示调用量、成本、活跃 Session 和供应商健康状态</li><li><strong>限流与并发控制</strong>：支持 RPM（每分钟请求数）、金额限制（5小时/周/月）、并发 Session 控制</li><li><strong>多供应商管理</strong>：同时接入 Claude、Codex、Gemini、OpenAI Compatible 等多种供应商</li><li><strong>智能负载均衡</strong>：权重 + 优先级 + 分组调度，内置熔断保护与最多 3 次自动故障转移</li></ul><h2 id="快速部署" tabindex="-1">快速部署 <a class="header-anchor" href="#快速部署" aria-label="Permalink to &quot;快速部署&quot;">​</a></h2><h3 id="一键脚本部署" tabindex="-1">一键脚本部署 <a class="header-anchor" href="#一键脚本部署" aria-label="Permalink to &quot;一键脚本部署&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 使用官方部署脚本，5 分钟完成安装</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://claude-code-hub.app/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>详细部署文档请参考：<a href="https://claude-code-hub.app/docs/deployment/script" target="_blank" rel="noreferrer">脚本部署指南</a></p><h3 id="客户端接入" tabindex="-1">客户端接入 <a class="header-anchor" href="#客户端接入" aria-label="Permalink to &quot;客户端接入&quot;">​</a></h3><p>部署完成后，将 Claude Code、Codex 等工具的 API 地址指向 CCH 代理即可使用。</p><p>详细接入文档请参考：<a href="https://claude-code-hub.app/docs/deployment/client-setup" target="_blank" rel="noreferrer">客户端接入指南</a></p><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><ul><li><strong>前端</strong>：Next.js</li><li><strong>后端</strong>：Hono</li><li><strong>数据库</strong>：PostgreSQL + Redis</li><li><strong>开源许可</strong>：MIT License</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="cch-和直接使用-api-有什么区别" tabindex="-1">CCH 和直接使用 API 有什么区别？ <a class="header-anchor" href="#cch-和直接使用-api-有什么区别" aria-label="Permalink to &quot;CCH 和直接使用 API 有什么区别？&quot;">​</a></h3><p>CCH 提供了供应商故障自动切换、负载均衡、用量统计、Session 粘性等团队级功能，单人使用直接配 API 即可，多人协作推荐使用 CCH。</p><h3 id="更多问题" tabindex="-1">更多问题 <a class="header-anchor" href="#更多问题" aria-label="Permalink to &quot;更多问题&quot;">​</a></h3><p>请查看 <a href="https://claude-code-hub.app/docs" target="_blank" rel="noreferrer">CCH 官方文档</a> 或加入 Telegram 交流群。</p>`,23)])])}const b=e(i,[["render",o]]);export{p as __pageData,b as default};
